import{_ as r,o as e,c as s,a2 as i}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"플랫폼 관리 프론트엔드","description":"","frontmatter":{"title":"플랫폼 관리 프론트엔드","feature_id":"006","status":"draft","created":"2026-05-31 16:20 (KST)","date":"2026-05-31T00:00:00.000Z","tags":["agent","platform","frontend","admin","vue","spa"]},"headers":[],"relativePath":"specs/006-platform-admin-frontend/spec.md","filePath":"specs/006-platform-admin-frontend/spec.md","lastUpdated":null}'),o={name:"specs/006-platform-admin-frontend/spec.md"};function a(n,t,l,d,c,g){return e(),s("div",null,[...t[0]||(t[0]=[i('<h1 id="spec-플랫폼-관리-프론트엔드-관리자-콘솔" tabindex="-1">Spec: 플랫폼 관리 프론트엔드 (관리자 콘솔) <a class="header-anchor" href="#spec-플랫폼-관리-프론트엔드-관리자-콘솔" aria-label="Permalink to &quot;Spec: 플랫폼 관리 프론트엔드 (관리자 콘솔)&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p>feature 004 가 22개 플랫폼 관리 기능의 <strong>백엔드(REST API)</strong> 를 완성했지만, 사용자가 그 기능을 쓸 <strong>화면이 없다</strong>. 현재는 정적 데모 페이지 한 장(<code>grid-demo.html</code>)뿐이라, 실무자가 로그인·사용자 관리·결재·감사 조회 같은 일을 하려면 API 를 직접 호출해야 한다.</p><p>이 기능은 그 22개 백엔드 기능을 실무자가 <strong>브라우저 화면에서 수행</strong>할 수 있는 <strong>관리자 콘솔(SPA)</strong> 을 만든다. 권한에 따라 메뉴가 동적으로 노출되고, 목록·검색·폼·결재 흐름을 화면으로 처리한다. feature 005 의 enabler(CORS·OpenAPI)로 별도 프론트 개발 서버와 타입 안전 API 연동의 토대는 이미 갖춰져 있다.</p><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><h3 id="포함" tabindex="-1">포함 <a class="header-anchor" href="#포함" aria-label="Permalink to &quot;포함&quot;">​</a></h3><p>브라우저에서 동작하는 <strong>단일 페이지 관리자 콘솔</strong>. 인증된 사용자가 자신의 권한 범위 안에서 플랫폼 기능을 화면으로 수행한다.</p><ul><li><strong>로그인/세션</strong> — 자격증명 로그인, 토큰 자동 갱신, 로그아웃, 세션 만료 처리.</li><li><strong>앱 셸</strong> — 권한 기반 동적 메뉴 네비게이션, 현재 사용자/로그아웃 헤더, 즐겨찾기.</li><li><strong>기능 화면</strong>(백엔드 22기능 대응): <ul><li>RBAC: 사용자·역할·부서(트리)·메뉴(트리·역할권한) 관리</li><li>메타데이터: 공통코드·다국어·시스템설정</li><li>감사: 7종 이력 조회(기간/행위자/키워드 필터)</li><li>결재: 양식·결재선 관리, 상신, 내 처리대기, 단계 승인/반려, 모니터링</li><li>권한 신청: 신청, 내 신청, (관리자) 승인/반려</li><li>메일: 양식·발송·현황·재발송 / 파일: 업로드·다운로드·삭제</li><li>내 프로필·비밀번호 변경</li></ul></li><li><strong>공통 UX</strong> — 목록(그리드: 검색·필터·페이징), 폼/다이얼로그(검증), 로딩/빈/오류 상태, 표준 응답(<code>ApiResponse</code>) 기반 토스트, 권한 거부(403)·인증 만료(401) 처리.</li></ul><h3 id="제외-non-goals" tabindex="-1">제외 (Non-goals) <a class="header-anchor" href="#제외-non-goals" aria-label="Permalink to &quot;제외 (Non-goals)&quot;">​</a></h3><ul><li>백엔드 변경 없음(004/005 API 를 소비만 한다). 새 엔드포인트 요구는 별도 처리.</li><li>모바일 전용 앱·오프라인 모드·실시간 푸시 알림은 범위 밖.</li><li>공개(비로그인) 페이지·외부 사용자 포털 없음(내부 관리자 콘솔).</li><li>langgraph4j 그래프/에이전트 UI(스튜디오)는 본 기능과 무관(기존 유지).</li></ul><h2 id="clarifications" tabindex="-1">Clarifications <a class="header-anchor" href="#clarifications" aria-label="Permalink to &quot;Clarifications&quot;">​</a></h2><h3 id="session-2026-05-31" tabindex="-1">Session 2026-05-31 <a class="header-anchor" href="#session-2026-05-31" aria-label="Permalink to &quot;Session 2026-05-31&quot;">​</a></h3><ul><li>Q: MVP(1차 독립 배포) 범위는? → A: <strong>FE1+FE2</strong>(로그인·앱셸 + RBAC). 이후 FE3~FE7 증분 추가.</li><li>Q: 프론트 디자인 시스템은? → A: <strong>Vuetify</strong>(Material, 이전 소스 <code>C:/ax/lego</code> 패턴 답습).</li><li>Q: 배포 형태는? → A: <strong>Spring 앱 static 통합</strong> — 빌드 산출물을 앱이 서빙(운영 동일 출처, CORS 불필요). 개발은 별도 dev server + 프록시.</li><li>Q: 화면 i18n 도입 시점은? → A: <strong>후속</strong>(MVP 한국어 1차, i18n 구조만 준비).</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><p>증분 우선순위(백엔드 US1~US7 대응, MVP 먼저):</p><table tabindex="0"><thead><tr><th>스토리</th><th>우선순위</th><th>내용</th></tr></thead><tbody><tr><td>FE1</td><td>P1 (MVP)</td><td><strong>로그인 &amp; 앱 셸</strong> — 로그인→권한 메뉴 네비게이션→내 정보/로그아웃, 세션 자동 갱신</td></tr><tr><td>FE2</td><td>P1 (MVP)</td><td><strong>RBAC 화면</strong> — 사용자·역할·부서·메뉴 CRUD + 역할↔메뉴 권한 설정</td></tr><tr><td>FE3</td><td>P2</td><td><strong>메타데이터 화면</strong> — 공통코드·다국어·시스템설정 관리</td></tr><tr><td>FE4</td><td>P2</td><td><strong>감사 이력 화면</strong> — 7종 이력 기간/필터 조회</td></tr><tr><td>FE5</td><td>P2</td><td><strong>결재 화면</strong> — 상신·내 처리대기·단계 승인/반려·모니터링(다단계)</td></tr><tr><td>FE6</td><td>P3</td><td><strong>권한 신청 화면</strong> — 신청·내 신청·승인/반려</td></tr><tr><td>FE7</td><td>P3</td><td><strong>메일·파일 화면</strong> — 메일 양식/발송/현황, 파일 업로드/다운로드</td></tr></tbody></table><p>상세 흐름(대표):</p><ol><li><strong>FE1</strong> — 사용자가 로그인하면 토큰을 받아 보관하고, 좌측 네비게이션에 <strong>자신이 접근 가능한 메뉴만</strong> 표시된다(<code>/menus/my</code>). 토큰 만료가 임박하면 자동 갱신되어 작업이 끊기지 않고, 갱신 불가 시 로그인 화면으로 안내된다.</li><li><strong>FE2</strong> — 관리자가 &quot;사용자 관리&quot;에서 목록을 검색·페이징으로 보고, 사용자를 생성하고 역할을 배정한 뒤 저장하면 화면에 즉시 반영된다. 권한이 없는 사용자는 이 메뉴가 보이지 않으며, 직접 진입을 시도해도 거부 안내를 받는다.</li><li><strong>FE5</strong> — 결재자가 &quot;내 처리대기&quot;에서 문서를 열어 현재 단계를 승인하면 다음 단계로 넘어가고, 최종 단계 승인 시 완료로 표시된다. 관리자는 모니터링에서 진행/지연을 본다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="기능-functional" tabindex="-1">기능 (Functional) <a class="header-anchor" href="#기능-functional" aria-label="Permalink to &quot;기능 (Functional)&quot;">​</a></h3><ul><li><strong>FR-1 (인증/세션)</strong>: 사용자는 화면에서 로그인/로그아웃할 수 있고, 인증 토큰은 갱신 주기에 맞춰 자동 갱신된다. 미인증 상태로 보호 화면 접근 시 로그인 화면으로 보낸다.</li><li><strong>FR-2 (동적 메뉴/접근통제)</strong>: 네비게이션은 사용자의 접근 가능 메뉴만 표시하고, 권한 없는 화면 라우트 진입은 차단한다(백엔드 권한 통제와 일치).</li><li><strong>FR-3 (기능 수행)</strong>: 각 기능 화면은 해당 백엔드 동작(목록/조회/생성/수정/삭제/상태전이)을 코드·콘솔 없이 화면으로 완수할 수 있게 한다.</li><li><strong>FR-4 (목록 UX)</strong>: 목록 화면은 검색·필터·페이징을 제공하며 대량 데이터에서도 응답성을 유지한다.</li><li><strong>FR-5 (입력 검증/오류)</strong>: 폼은 제출 전 검증하고, 서버 오류(검증 400·충돌 409·미존재 404·권한 403·서버 500)를 사용자 친화적 메시지로 표시한다(표준 <code>ApiResponse</code> 활용).</li><li><strong>FR-6 (다단계 결재 흐름)</strong>: 결재 화면은 상신·현재 단계 승인/반려·진행 상태·지연을 표현하고, 현재 단계 결재자만 처리 가능함을 화면에 반영한다.</li><li><strong>FR-7 (파일)</strong>: 파일 업로드/다운로드/삭제를 화면에서 수행하고 진행/결과를 안내한다.</li></ul><h3 id="비기능-non-functional" tabindex="-1">비기능 (Non-functional) <a class="header-anchor" href="#비기능-non-functional" aria-label="Permalink to &quot;비기능 (Non-functional)&quot;">​</a></h3><ul><li><strong>FR-8 (반응성)</strong>: 일반 화면 전환·목록 조회에서 사용자가 체감하는 지연이 작아야 한다.</li><li><strong>FR-9 (접근성/일관성)</strong>: 화면 간 레이아웃·상호작용·용어가 일관되며, 키보드 조작과 명확한 상태(로딩/빈/오류) 표시를 제공한다.</li><li><strong>FR-10 (안전한 빌드/배포)</strong>: 프론트는 백엔드와 독립적으로 개발·빌드되며, 배포 시 빌드 산출물을 Spring 앱 static 으로 통합 서빙한다(운영 동일 출처). 004 의 기존 동작·테스트에 영향이 없어야 한다.</li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><p>신규 데이터 엔터티 없음 — 004/005 의 API 응답을 화면 모델로 소비한다. 화면이 다루는 주요 개념: 사용자/역할/부서/메뉴, 공통코드·다국어·설정, 감사 이력(7종), 결재 문서·단계, 권한 신청, 메일 양식·발송, 파일.</p><h2 id="contracts-api-그래프-인터페이스" tabindex="-1">Contracts (API / 그래프 인터페이스) <a class="header-anchor" href="#contracts-api-그래프-인터페이스" aria-label="Permalink to &quot;Contracts (API / 그래프 인터페이스)&quot;">​</a></h2><p>신규 백엔드 엔드포인트 없음. 소비 대상:</p><ul><li>인증: <code>/api/v1/auth/{login,refresh,logout,me}</code>, 동적 메뉴 <code>/api/v1/menus/my</code>.</li><li>기능: 004 의 <code>/api/v1/{users,roles,depts,menus,codes,messages,settings,audit, approvals,permissions,mails,files}</code>.</li><li>005 enabler 의존: CORS 허용(별도 dev server), OpenAPI(<code>/v3/api-docs</code>) — 타입 클라이언트.</li></ul><h2 id="assumptions-정보-기반-결정-—-clarify-plan-에서-확정" tabindex="-1">Assumptions (정보 기반 결정 — clarify/plan 에서 확정) <a class="header-anchor" href="#assumptions-정보-기반-결정-—-clarify-plan-에서-확정" aria-label="Permalink to &quot;Assumptions (정보 기반 결정 — clarify/plan 에서 확정)&quot;">​</a></h2><ul><li><strong>스택</strong>(확정): Vue 3 + TypeScript + Vite, 별도 dev server + 프록시(005 결정). 상태관리· 라우팅은 Vue 생태계 표준. UI 는 <strong>Vuetify</strong>(Material) — 이전 소스 <code>C:/ax/lego</code> (Vue3/Vuetify/Pinia) 패턴 답습. 목록 그리드는 반입된 <strong>VuGrid</strong>(Vue 래퍼) 활용.</li><li><strong>API 클라이언트</strong>: 005 의 OpenAPI(<code>/v3/api-docs</code>)로 타입 안전 클라이언트를 생성/활용.</li><li><strong>인증 저장</strong>: Access 토큰은 메모리/적절한 클라이언트 저장소, 갱신은 Refresh 토큰 흐름. 401 인터셉트→refresh→재시도, 실패 시 로그인 유도.</li><li><strong>언어</strong>(확정): 한국어 1차. 화면 i18n(다국어 <code>/messages</code> 연동)은 <strong>후속</strong> 단계 — MVP 는 i18n 구조만 준비.</li><li><strong>증분 진행</strong>(확정): <strong>MVP = FE1+FE2</strong> 먼저 독립 배포·검증 후 FE3~FE7 증분 추가(백엔드 답습).</li><li><strong>배포 통합</strong>(확정): 개발은 dev server + 프록시, <strong>배포는 빌드 산출물을 Spring 앱 static 으로 통합 서빙</strong>(운영 동일 출처 → CORS 불필요). 003 VuGrid 정적 서빙과 일관.</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: 사용자는 로그인 후 자신의 권한 메뉴만 네비게이션에서 보고, 권한 없는 화면엔 진입할 수 없다(우회 0).</li><li><strong>SC-2</strong>: 관리자는 사용자 생성→역할 배정→저장의 전체 작업을 <strong>화면만으로</strong> 완료한다.</li><li><strong>SC-3</strong>: 목록 화면에서 검색·필터·페이징으로 대량 데이터를 다룰 수 있고 사용자가 지연을 거의 느끼지 않는다.</li><li><strong>SC-4</strong>: 세션 만료가 임박해도 자동 갱신으로 진행 중 작업이 끊기지 않으며, 갱신 불가 시 명확히 재로그인으로 안내된다.</li><li><strong>SC-5</strong>: 모든 서버 오류(검증·충돌·미존재·권한·서버)가 화면에서 사용자 친화적 메시지로 표시된다(원시 오류 노출 0).</li><li><strong>SC-6</strong>: 다단계 결재를 화면에서 상신→단계 승인→완료까지 끝낼 수 있고, 현재 단계 결재자만 처리 가능함이 반영된다.</li><li><strong>SC-7 (MVP 게이트)</strong>: FE1·FE2 만으로도 로그인·RBAC 운영이 독립적으로 가능하다.</li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>[x] <s>MVP 범위</s> → FE1+FE2 (Clarifications 2026-05-31)</li><li>[x] <s>디자인 시스템</s> → Vuetify</li><li>[x] <s>배포 형태</s> → Spring static 통합</li><li>[x] <s>i18n 도입 시점</s> → 후속(한국어 1차)</li></ul><p>남은 결정 없음 — <code>/speckit-plan</code> 진행 가능.</p>',35)])])}const p=r(o,[["render",a]]);export{h as __pageData,p as default};
